import{c as o,S as a,j as c,m as d}from"./chunks/framework.DvQr6YbT.js";const b=JSON.parse('{"title":"稳定性契约","description":"","frontmatter":{},"headers":[],"relativePath":"zh/reference/stability.md","filePath":"zh/reference/stability.md","lastUpdated":1783505267000}'),l={name:"zh/reference/stability.md"};function i(r,e,t,n,s,h){return a(),c("div",null,[...e[0]||(e[0]=[d('<h1 id="稳定性契约" tabindex="-1">稳定性契约 <a class="header-anchor" href="#稳定性契约" aria-label="Permalink to “稳定性契约”">​</a></h1><p>自 1.0.0 起，下列表面在 semver 下冻结：<strong>破坏其中任何一项都需要主版本号</strong>。 minor 和 patch 更新可以向这些表面<em>添加</em>内容，但绝不改变或移除既有含义。 本页的每一条承诺都由仓库中的契约测试（<code>tests/contract/</code>）钉住——冻结由 CI 强制，而不是靠善意。</p><h2 id="_1-x-更新可以对你做什么" tabindex="-1">1.x 更新可以对你做什么 <a class="header-anchor" href="#_1-x-更新可以对你做什么" aria-label="Permalink to “1.x 更新可以对你做什么”">​</a></h2><p>新增命令、旗标、工具、可选字段和可选文件。改进检索分数。修复 bug。 更新技能内容。</p><h2 id="_1-x-更新绝不会对你做什么" tabindex="-1">1.x 更新绝不会对你做什么 <a class="header-anchor" href="#_1-x-更新绝不会对你做什么" aria-label="Permalink to “1.x 更新绝不会对你做什么”">​</a></h2><p>移除或重命名命令、旗标或工具；改变既有文件或字段的含义；改变 JSON 输出的 键；破坏 1.0.0 创建的工作区或知识包。</p><h2 id="冻结的表面" tabindex="-1">冻结的表面 <a class="header-anchor" href="#冻结的表面" aria-label="Permalink to “冻结的表面”">​</a></h2><h3 id="工作区格式" tabindex="-1">工作区格式 <a class="header-anchor" href="#工作区格式" aria-label="Permalink to “工作区格式”">​</a></h3><ul><li><code>KNOWLEDGE.md</code>、<code>SCHEMA.md</code>、<code>INDEX.base</code>、四个编译目录（<code>entities/</code>、 <code>concepts/</code>、<code>comparisons/</code>、<code>queries/</code>）、<code>inbox/</code>、<code>Library/&lt;bundle-id&gt;/</code> 的含义和位置。</li><li><code>.knowlery/manifest.json</code>（既有字段）和 <code>.knowlery/bundles.json</code> （schemaVersion 1）。任何 1.x 永远能读取 1.0.0 写下的状态。</li><li>页面层级规则（编译目录是 agent 层级；其余一切是用户层级）。</li></ul><h3 id="cli-表面" tabindex="-1">CLI 表面 <a class="header-anchor" href="#cli-表面" aria-label="Permalink to “CLI 表面”">​</a></h3><ul><li>1.0 发布的每个命令和子命令、它们的位置参数数量和旗标。</li><li><code>--json</code> 输出形状：既有键永不改变；新增键属于 minor。</li><li>退出码语义：<code>0</code> 成功——<strong>包括发现</strong>（弃答的查询、空报告）；<code>1</code> 操作 失败；<code>2</code> 用法错误。</li><li><code>--kb</code> / <code>--dir</code> 解析规则：<code>--kb</code> 经注册表解析、<code>--dir</code> 永久有效、两者 同传是错误、注册表永远不是前置条件。</li></ul><h3 id="mcp-契约" tabindex="-1">MCP 契约 <a class="header-anchor" href="#mcp-契约" aria-label="Permalink to “MCP 契约”">​</a></h3><ul><li>八个工具名（<code>list_kbs</code>、<code>query</code>、<code>stale</code>、<code>health</code>、<code>list_bundles</code>、 <code>init_kb</code>、<code>capture</code>、<code>sync</code>）、它们的输入 schema（必填字段和类型；新增 <em>可选</em>输入属于 minor）以及 <code>structuredContent</code> 形状（既有键）。广播的 schema 携带冻结的键——客户端通过 <code>tools/list</code> 内省到的就是契约本身， 且服务器在运行时对每个结果做校验。</li><li>发现与错误的语义：弃答、<code>healthy: false</code>、很长的 stale 报告是成功结果； 工具错误只留给坏掉的调用。</li><li>九个提示词名、<code>knowlery://{kb}/{+path}</code> 资源方案，以及可读层白名单边界。</li><li><code>knowlery mcp serve</code> 的旗标和认证契约（bearer token、401 形状）。</li></ul><h3 id="知识包格式-okf" tabindex="-1">知识包格式（OKF） <a class="header-anchor" href="#知识包格式-okf" aria-label="Permalink to “知识包格式（OKF）”">​</a></h3><ul><li><code>knowlery-bundle.json</code> schemaVersion 1 的字段和 zip 布局（<code>index.md</code>、 <code>agent-index.json</code>、<code>_sources/</code>、更新日志）。</li><li>安装/更新门禁语义：版本必须递增、本地修改拒绝覆盖。</li></ul><h3 id="kb-注册表" tabindex="-1">KB 注册表 <a class="header-anchor" href="#kb-注册表" aria-label="Permalink to “KB 注册表”">​</a></h3><ul><li><code>registry.json</code> schemaVersion 1、名字语法（<code>[a-z0-9][a-z0-9-_]</code>，最长 64 字符）、保留名（<code>*</code>、<code>all</code>），以及&quot;损坏即响亮报错&quot;规则（受损的注册表 会被报告，绝不静默重置）。</li></ul><h2 id="明确不冻结的" tabindex="-1">明确不冻结的 <a class="header-anchor" href="#明确不冻结的" aria-label="Permalink to “明确不冻结的”">​</a></h2><p>同样直白地说出来，让&quot;没有承诺&quot;永远不会被误认为承诺：</p><ul><li><strong>检索排序内部。</strong> 分数、候选之间的排序、置信门禁的阈值可以在任何版本 改进。契约是结果的<em>形状</em>和弃答判定串（<code>no-confident-match</code>），不是数字。</li><li><strong>技能文本。</strong> 技能内容会演进；技能<em>名字</em>是契约。</li><li><strong><code>health</code> 的 <code>config</code> 对象的内部键。</strong> 各检查字段可以随健康检查器演进 而增加、重命名或退役——冻结它们等于冻结检查本身。它的契约是 <code>healthy</code> （布尔值）加上 <code>config</code> 对象的存在。</li><li><strong>插件 UI</strong>（dashboard 布局、弹窗、设置组织）、<strong>文档</strong>、<strong>eval 阈值</strong>。</li><li>上面未列出的 <code>.knowlery/</code> 私有状态（活动回执、报告、freshness 文件）。</li><li>TypeScript 内部：<code>src/</code> 不是公开 API；从包中 import 不受支持。</li></ul><h2 id="弃用路径" tabindex="-1">弃用路径 <a class="header-anchor" href="#弃用路径" aria-label="Permalink to “弃用路径”">​</a></h2><p>一个表面可以在 minor 版本中获得继任者（新旗标、新工具）；旧的持续工作， 直到某个主版本移除它。别名不算破坏。</p>',22)])])}const p=o(l,[["render",i]]);export{b as __pageData,p as default};
